code = """import json

# Load NASDAQ Capital Market tickers
tickers_list = []
tickers_file = 'var_functions.query_db_102.json'
try:
    with open(tickers_file, 'r') as f:
        raw_data = json.load(f)
        tickers_list = [item['Symbol'] for item in raw_data]
except:
    # Try direct variable
    try:
        raw_data = locals()['var_functions.query_db_102']
        tickers_list = [item['Symbol'] for item in raw_data]
    except:
        # Fallback query
        result = query_db("stockinfo_database", "SELECT Symbol FROM stockinfo WHERE MARKET_CATEGORY = 'S'")
        if isinstance(result, list):
            tickers_list = [item['Symbol'] for item in result]

print("Total tickers:", len(tickers_list))
print("First 10:", tickers_list[:10])

# Analyze each ticker
all_results = []
processed = 0

for ticker in tickers_list:
    processed += 1
    try:
        # Get 2019 data
        query = f"SELECT Date, High, Low FROM {ticker} WHERE Date LIKE '2019-%'"
        stock_data = query_db("stocktrade_database", query)
        
        if not stock_data or isinstance(stock_data, dict):
            continue
            
        # Count high volatility days
        high_vol_days = 0
        for day in stock_data:
            try:
                high = float(day.get('High', 0))
                low = float(day.get('Low', 0))
                if low > 0:
                    intraday_range = high - low
                    pct_of_low = intraday_range / low
                    if pct_of_low > 0.20:
                        high_vol_days += 1
            except:
                continue
        
        if high_vol_days > 0:
            all_results.append({
                'ticker': ticker,
                'high_vol_days': high_vol_days
            })
            
        if processed % 20 == 0:
            print(f"Processed {processed}, found {len(all_results)} volatile stocks")
            
    except:
        continue

# Sort by high volatility days
all_results.sort(key=lambda x: x['high_vol_days'], reverse=True)

print("\\nTop 10:")
for i, res in enumerate(all_results[:10]):
    print(f"{i+1}. {res['ticker']}: {res['high_vol_days']} days")

print("__RESULT__:")
print(json.dumps(all_results[:10]))"""

